/** Centralized form labels — prep for FormLabels API (GAP-P3-05). */
import type { CashVoucherKind } from '../components/kt/CashVoucherList';
import type { CashVoucherShellId } from '../features/kt/cash-voucher/shared/config/cashVoucherShellProfiles';
import {
  formatPartnerFieldLabel,
  PARTNER_FIELD_PLACEHOLDER,
  resolvePartnerSideLabel,
} from './partnerFieldLabels';

export interface CashVoucherFormLabels {
  title: string;
  createTitle: string;
  saveNew: string;
  saveEdit: string;
  /** Nút Lưu trên VoucherFormToolbar */
  saveButton: string;
  /** «Bên tương ứng» — map theo shell (Bên nộp / Bên nhận / …). */
  partnerSideLabel: string;
  /** `Đối tượng ({partnerSideLabel})` — validation; UI dùng `formatPartnerFieldLabelWithType`. */
  partnerLabel: string;
  /** Placeholder ô tìm đối tượng header */
  partnerPlaceholder: string;
  /** Ô nhập tên — thay cho «— tên hiển thị» sau partnerLabel */
  representativeLabel: string;
  cashLabel: string;
  lineThAccount: string;
  totalLabel: string;
  sectionHeader: string;
  sectionLines: string;
  /** Toggle §8.10.3 — compact header (phiếu thu) */
  headerExpand: string;
  headerCollapse: string;
  voucherDate: string;
  voucherCode: string;
  /** FM sync — hiển thị khi khác mã Linm */
  legacyCode: string;
  currency: string;
  exchangeRate: string;
  customerPhone: string;
  reference: string;
  description: string;
  lineAmount: string;
  lineDesc: string;
  costCenter: string;
  lineCustomer: string;
  receiptKind: string;
  processingLevel: string;
  addLine: string;
  copyLine: string;
  allocateInvoices: string;
  postingReasonCode: string;
  paymentChannelCode: string;
  allowEditPostingAccounts: string;
  invoiceCode: string;
  invoiceDate: string;
  invoiceTotal: string;
  invoicePaid: string;
  invoiceRemaining: string;
}

const BASE_LABELS: Omit<
  CashVoucherFormLabels,
  | 'partnerSideLabel'
  | 'partnerLabel'
  | 'partnerPlaceholder'
  | 'title'
  | 'createTitle'
  | 'saveNew'
  | 'cashLabel'
  | 'lineThAccount'
  | 'totalLabel'
> = {
  saveEdit: 'Lưu thay đổi',
  saveButton: 'Lưu',
  representativeLabel: 'Người đại diện',
  sectionHeader: 'Thông tin chứng từ',
  headerExpand: 'Hiện thêm thông tin',
  headerCollapse: 'Thu gọn',
  sectionLines: 'Chi tiết định khoản',
  voucherDate: 'Ngày chứng từ',
  voucherCode: 'Số chứng từ',
  legacyCode: 'Mã gốc',
  currency: 'Ngoại tệ',
  exchangeRate: 'Tỷ giá',
  customerPhone: 'Số điện thoại',
  reference: 'Số tham chiếu (HĐ)',
  description: 'Diễn giải',
  lineAmount: 'Số tiền',
  lineDesc: 'Diễn giải dòng',
  costCenter: 'Mã vụ việc',
  lineCustomer: 'Đối tượng dòng',
  receiptKind: 'Loại phiếu / Nhóm đối tượng',
  processingLevel: 'Mức xử lý',
  postingReasonCode: 'Lý do / Định khoản',
  paymentChannelCode: 'Hình thức thanh toán',
  allowEditPostingAccounts: 'Cho phép sửa TK định khoản',
  addLine: '+ Thêm định khoản',
  copyLine: 'Sao chép dòng',
  allocateInvoices: 'Phân bổ hóa đơn bán hàng',
  invoiceCode: 'Số HĐ',
  invoiceDate: 'Ngày HĐ',
  invoiceTotal: 'Tiền HĐ',
  invoicePaid: 'Đã TT',
  invoiceRemaining: 'Còn lại',
};

function buildPartnerLabels(shellId: CashVoucherShellId, kind: CashVoucherKind) {
  const partnerSideLabel = resolvePartnerSideLabel(shellId, kind);
  return {
    partnerSideLabel,
    partnerLabel: formatPartnerFieldLabel(partnerSideLabel),
    partnerPlaceholder: PARTNER_FIELD_PLACEHOLDER,
  };
}

type KindCashLabels = Pick<CashVoucherFormLabels, 'cashLabel' | 'lineThAccount' | 'totalLabel'>;

function labelsForShell(
  shellId: CashVoucherShellId,
  kind: CashVoucherKind,
  title: string,
  createTitle: string,
  kindLabels: KindCashLabels,
  overrides: Partial<CashVoucherFormLabels> = {},
): CashVoucherFormLabels {
  return {
    ...BASE_LABELS,
    ...kindLabels,
    ...buildPartnerLabels(shellId, kind),
    title,
    createTitle,
    saveNew: createTitle,
    ...overrides,
  };
}

const RECEIPT = labelsForShell('phieu-thu', 'receipt', 'Phiếu thu tiền mặt', 'Tạo phiếu thu tiền mặt', {
  cashLabel: 'TK thu (TK tiền mặt)',
  lineThAccount: 'TK đối ứng (TK Có)',
  totalLabel: 'Tổng tiền thu',
});

const PAYMENT = labelsForShell('phieu-chi', 'payment', 'Phiếu chi tiền mặt', 'Tạo phiếu chi tiền mặt', {
  cashLabel: 'TK chi (TK tiền mặt)',
  lineThAccount: 'TK đối ứng (TK Nợ)',
  totalLabel: 'Tổng tiền chi',
});

export function getCashVoucherFormLabels(kind: CashVoucherKind): CashVoucherFormLabels {
  return kind === 'receipt' ? RECEIPT : PAYMENT;
}

/** Field overrides theo shell BC1/BN1/UNC — kế thừa PT/PC; partner map từ `PARTNER_SIDE_LABELS`. */
const SHELL_LABEL_OVERRIDES: Partial<Record<CashVoucherShellId, Partial<CashVoucherFormLabels>>> = {
  'giay-bao-co': {
    cashLabel: 'TK tiền gửi (TK Nợ)',
    totalLabel: 'Tổng tiền thu gửi',
    paymentChannelCode: 'Tài khoản ngân hàng',
    voucherCode: 'Số thu tiền gửi',
  },
  'giay-bao-no': {
    cashLabel: 'TK tiền gửi (TK Có)',
    totalLabel: 'Tổng tiền chi gửi',
    paymentChannelCode: 'Tài khoản ngân hàng',
    voucherCode: 'Số chi tiền gửi',
  },
  'uy-nhiem-chi': {
    cashLabel: 'TK trích nợ (TK Có)',
    totalLabel: 'Tổng tiền ủy nhiệm chi',
    paymentChannelCode: 'Tài khoản ngân hàng',
    voucherCode: 'Số UNC',
    reference: 'Số tham chiếu UNC',
  },
};

/** Bank shells (giấy báo có/nợ, UNC) — title + field labels theo route. */
export function getCashVoucherFormLabelsForShell(
  shellId: CashVoucherShellId,
  pageTitle: string,
  kind: CashVoucherKind,
): CashVoucherFormLabels {
  const base = getCashVoucherFormLabels(kind);
  const overrides = SHELL_LABEL_OVERRIDES[shellId];
  const createTitle = `Tạo ${pageTitle.charAt(0).toLowerCase()}${pageTitle.slice(1)}`;
  const partner = buildPartnerLabels(shellId, kind);
  return {
    ...base,
    ...partner,
    ...(overrides ?? {}),
    title: pageTitle,
    createTitle,
    saveNew: createTitle,
  };
}


